mapper.select:
SELECT R.*, (SELECT COUNT(*) FROM TB_DEV_COMMENT C WHERE C.REQ_SEQ = R.REQ_SEQ AND C.DEL_YN = 'N') AS commentCnt FROM TB_DEV_REQUEST R WHERE R.DEL_YN = 'N'
AND R.REQ_TYPE = #{searchType}
AND R.STATUS = #{searchStatus}
AND R.TITLE LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY R.REG_DT DESC
